Code.Terraform:
```hcl
# 配置包含两个源的源组，并在默认缓存行为中使用它
resource "aws_cloudfront_distribution" "<example_resource_name>" {
  enabled = true

  origin {
    domain_name = "<primary_origin_domain>"
    origin_id   = "primary"
    s3_origin_config {}
  }

  origin {
    domain_name = "<secondary_origin_domain>"
    origin_id   = "secondary"
    s3_origin_config {}
  }

  origin_group {
    origin_id = "<example_origin_group_id>"  # 关键：定义包含 2 个源的源组
    failover_criteria {
      status_codes = [500]  # 关键：在 500 时故障转移以启用源故障转移
    }
    member { origin_id = "primary" }
    member { origin_id = "secondary" }
  }

  default_cache_behavior {
    target_origin_id       = "<example_origin_group_id>"  # 关键：使用源组处理请求
    viewer_protocol_policy = "allow-all"
    forwarded_values {
      query_string = false
      cookies { forward = "none" }
    }
  }

  restrictions {
    geo_restriction { restriction_type = "none" }
  }

  viewer_certificate { cloudfront_default_certificate = true }
}
```
